example.code:
// Good
interface Config {
  readonly host: string;
  readonly port: number;
  readonly tags: readonly string[];
}

function process(items: readonly Item[]): Result[] {
  return items.map(transform); // no mutation
}

// Bad - mutable by default
interface Config {
  host: string;
  port: number;
  tags: string[];
}

// Good
const PERMISSIONS = ["read", "write", "admin"] as const;
type Permission = (typeof PERMISSIONS)[number]; // "read" | "write" | "admin"

// Good - pure transformation
function applyDiscount(price: number, rate: number): number {
  return price * (1 - rate);
}

// Bad - mutates external state
let total = 0;
function addToTotal(amount: number): void {
  total += amount;
}

// Good - return new object
function updateName(user: User, name: string): User {
  return { ...user, name };
}

// Good - return new array
function addItem(items: readonly Item[], item: Item): Item[] {
  return [...items, item];
}

// Bad - mutates input
function updateName(user: User, name: string): void {
  user.name = name;
}

// Good
const activeNames = users
  .filter((u) => u.active)
  .map((u) => u.name);

// Bad - imperative mutation
const activeNames: string[] = [];
for (let i = 0; i < users.length; i++) {
  if (users[i].active) {
    activeNames.push(users[i].name);
  }
}

// Good - inject dependencies
export function createService(config: Config): Service {
  return { ... };
}

// Bad - mutable module state
let connectionPool: Pool | null = null;
export function getPool(): Pool {
  if (!connectionPool) connectionPool = createPool();
  return connectionPool;
}
